queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?dutyfreeshops a :Duty_Free_Shops .
    ?dutyfreeshops p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?souvenirstores a :SouvenirStores .
    ?souvenirstores p:name ?name .
    ?souvenirstores p:location ?location_f .
    FILTER(STR(?location_f) = "Terminal 3")
    BIND(?name AS ?o0)
  }
}

